mapper.select:
select m.id, m.project_id, m.submit_time, m.contact_name, m.contact_phone, m.result_type, m.extra_data::text as extra_data, m.del_flag, m.create_by, m.create_time, m.update_by, m.update_time, m.remark, p.project_name from proj_material m left join proj_project p on p.id = m.project_id where m.del_flag = '0'
and m.project_id = #{projectId}
and m.contact_name like concat('%', #{contactName}, '%')
and m.result_type = #{resultType}
order by m.id desc

mapper.update:
update proj_material
project_id = #{projectId}, submit_time = #{submitTime}, contact_name = #{contactName}, contact_phone = #{contactPhone}, result_type = #{resultType}, extra_data = #{extraData}::jsonb, remark = #{remark}, update_by = #{updateBy}, update_time = now()
where id = #{id}
